={{ JSON.stringify({
  source: "telegram",
  intent: $json.intent,
  content_type: $json.content_type,
  title: null,
  author: null,
  capture_text: $json.capture_text,
  clean_text: $json.clean_text,
  url: $json.url ?? null,
  url_canonical: $json.url_canonical ?? null,

  topic_primary: null,
  topic_primary_confidence: null,
  topic_secondary: null,
  topic_secondary_confidence: null,
  gist: null,

  idempotency_policy_key: $json.idempotency_policy_key,
  idempotency_key_primary: $json.idempotency_key_primary,
  idempotency_key_secondary: $json.idempotency_key_secondary, 

  // nested JSON stays nested
  metadata: (() => {
    const baseMeta = $json.metadata_patch ?? ($json.retrieval ? { retrieval: $json.retrieval } : null);
    const smokeRunId = String($json.test_run_id || '').trim();
    if ($json.smoke_mode === true && smokeRunId) {
      return { ...(baseMeta || {}), smoke: { suite: 'T00', run_id: smokeRunId } };
    }
    return baseMeta;
  })(),

  retrieval_excerpt: $json.retrieval?.excerpt ?? null,
  retrieval_version: $json.retrieval?.version ?? null,
  source_domain: $json.retrieval?.source_domain ?? null,

  clean_word_count: $json.retrieval?.quality?.clean_word_count ?? null,
  clean_char_count: $json.retrieval?.quality?.clean_char_count ?? null,
  extracted_char_count: $json.retrieval?.quality?.extracted_char_count ?? null,
  link_count: $json.retrieval?.quality?.link_count ?? null,
  link_ratio: $json.retrieval?.quality?.link_ratio ?? null,
  boilerplate_heavy: $json.retrieval?.quality?.boilerplate_heavy ?? null,
  low_signal: $json.retrieval?.quality?.low_signal ?? null,
  extraction_incomplete: $json.retrieval?.quality?.extraction_incomplete ?? null,
  quality_score: $json.retrieval?.quality?.quality_score ?? null,

  returning: [
    "entry_id","id","created_at","source","intent","content_type","title","author","url","url_canonical","capture_text","COALESCE(char_length(capture_text), 0) AS text_len"
  ]
}) }}

