'use strict';

function mdv2(value) {
  return String(value ?? '').replace(/[\\_*\[\]()~`>#+\-=|{}.!]/g, '\\$&');
}

function mdv2Message(value, options) {
  const maxLen = Number((options && options.maxLen) || 4000);
  const text = mdv2(value);
  return text.length > maxLen ? text.slice(0, Math.max(0, maxLen - 3)) + '...' : text;
}
const entryId = String($json.entry_id ?? 'unknown').trim() || 'unknown';
  return [{ json: { ...$json, telegram_message: mdv2Message('Duplicate telegram entry ' + entryId + ' processing stopped') } }];

'use strict';

function mdv2Message(value) {
  const escaped = String(value ?? '').replace(/[\\_*\[\]()~`>#+\-=|{}.!]/g, '\\$&');
  return escaped.length > 4000 ? escaped.slice(0, 3997) + '...' : escaped;
}

const entryId = String($json.entry_id ?? 'unknown').trim() || 'unknown';
const action = String($json.action ?? 'inserted').trim() || 'inserted';
const text = 'Thought saved as entry ' + entryId + ' operation ' + action;

return [{ json: { ...$json, telegram_message: mdv2Message(text) } }];

'use strict';

const assertions = Array.isArray($json.smoke_assertions) ? [...$json.smoke_assertions] : [];
assertions.push({ name: 'normalize_ok', ok: !!$json.intent && !!$json.content_type && !!$json.capture_text });
return [{ json: { ...$json, smoke_assertions: assertions } }];

'use strict';

const assertions = Array.isArray($json.smoke_assertions) ? [...$json.smoke_assertions] : [];
const action = String($json.action || '').trim();
const actionOk = action === 'inserted' || action === 'updated' || action === 'skipped';
const entryIdOk = action === 'skipped' ? true : !!$json.entry_id;
assertions.push({ name: 'insert_action_valid', ok: actionOk, action });
assertions.push({ name: 'entry_id_present', ok: entryIdOk, entry_id: $json.entry_id ?? null });
return [{ json: { ...$json, smoke_assertions: assertions } }];

'use strict';

const assertions = Array.isArray($json.smoke_assertions) ? [...$json.smoke_assertions] : [];
const hasUrl = !!($json.url || $json.url_canonical);
const ok = !hasUrl || !!($json.clean_text || $json.capture_text);
assertions.push({ name: 'web_extraction_path_ok', ok, has_url: hasUrl });
return [{ json: { ...$json, smoke_assertions: assertions } }];

'use strict';

const assertions = Array.isArray($json.smoke_assertions) ? [...$json.smoke_assertions] : [];
const ok = !$json.error;
assertions.push({ name: 'tier1_ok', ok });
return [{ json: { ...$json, smoke_assertions: assertions } }];

'use strict';

const assertions = Array.isArray($json.smoke_assertions) ? [...$json.smoke_assertions] : [];
const msg = String($json.telegram_message || '');
assertions.push({ name: 'format_message_non_empty', ok: msg.length > 0 });
return [{ json: { ...$json, smoke_assertions: assertions } }];

'use strict';

const assertions = Array.isArray($json.smoke_assertions) ? [...$json.smoke_assertions] : [];
const msg = String($json.telegram_message || '');
assertions.push({ name: 'format_duplicate_non_empty', ok: msg.length > 0 });
return [{ json: { ...$json, smoke_assertions: assertions } }];

'use strict';

const assertions = Array.isArray($json.smoke_assertions) ? [...$json.smoke_assertions] : [];
const msg = String($json.telegram_message || '');
assertions.push({ name: 'format_thought_non_empty', ok: msg.length > 0 });
return [{ json: { ...$json, smoke_assertions: assertions } }];

'use strict';

const assertions = Array.isArray($json.smoke_assertions) ? [...$json.smoke_assertions] : [];
const msg = String($json.telegram_message || '');
assertions.push({ name: 'telegram_send_message_present', ok: msg.length > 0 });
const telegramMessageId = $json.message_id ?? ($json.result && $json.result.message_id) ?? null;
if (telegramMessageId != null) {
  assertions.push({ name: 'telegram_message_id_present', ok: true });
}
const ok = assertions.every((a) => a.ok === true);
return [{
  json: {
    ...$json,
    test_case: 'telegram_capture',
    ok,
    run_id: $json.test_run_id || null,
    artifacts: {
      entry_id: $json.entry_id ?? null,
      action: $json.action ?? null,
      telegram_message: msg || null,
      telegram_message_id: telegramMessageId,
    },
    assertions,
    error: ok ? null : { message: 'telegram capture assertions failed' },
  },
}];

'use strict';

const inputText = String($json.raw_text || ($json.message && ($json.message.text || $json.message.caption)) || '').trim();
const URL_RE = /(https?:\/\/[^\s<>()]+|www\.[^\s<>()]+)/ig;
const matches = inputText.match(URL_RE) || [];
const seen = new Set();
const urls = matches
  .map((u) => {
    let v = String(u || '').trim();
    while (/[)\],.?!:;"'»]+$/.test(v)) v = v.replace(/[)\],.?!:;"'»]+$/, '');
    if (/^www\./i.test(v)) v = `https://${v}`;
    return v;
  })
  .filter(Boolean)
  .filter((u) => {
    const k = u.toLowerCase();
    if (seen.has(k)) return false;
    seen.add(k);
    return true;
  });

const textWithoutUrls = inputText
  .replace(URL_RE, ' ')
  .replace(/[\t\r\n,;|\u2022]+/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

const residue = textWithoutUrls
  .replace(/[()\[\]{}<>0-9.\-_:]/g, '')
  .trim();

const hasUrls = urls.length > 0;
const isUrlOnly = hasUrls && residue.length === 0;
const mode = isUrlOnly ? 'url' : 'thought';
const normalizedThoughtText = hasUrls && !isUrlOnly ? textWithoutUrls : inputText;

const assertions = Array.isArray($json.smoke_assertions) ? [...$json.smoke_assertions] : [];
assertions.push({ name: 'telegram_mode_routed', ok: true, mode, url_count: urls.length, mixed: hasUrls && !isUrlOnly });

return [{
  json: {
    ...$json,
    raw_text: normalizedThoughtText,
    raw_text_original: inputText,
    telegram_capture_mode: mode,
    telegram_url_count: urls.length,
    telegram_urls: urls,
    telegram_mode_error: null,
    smoke_assertions: assertions,
  },
}];

'use strict';

const urls = Array.isArray($json.telegram_urls) ? $json.telegram_urls.filter(Boolean) : [];
if (!urls.length) return [];

const source = {
  system: 'telegram',
  chat_id: $json.telegram_chat_id || ($json.message && $json.message.chat && $json.message.chat.id) || null,
  message_id: $json.telegram_message_id || ($json.message && $json.message.message_id) || null,
  user_id: $json.telegram_user_id || ($json.message && $json.message.from && $json.message.from.id) || null,
};

return urls.map((url, idx) => {
  const u = String(url);
  return {
    json: {
      ...$json,
      raw_text: u,
      url: u,
      url_canonical: u,
      content_type: 'newsletter',
      source,
      telegram_url_index: idx,
    },
  };
});
